func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	type cand struct {
		idx       int
		costDelta float64
		feasible  bool
	}
	for oi := 0; oi < orderCount; oi++ {
		ori, des := oris[oi], dess[oi]
		bestCands := make([]cand, 0, MAXASSIGNS)
		for ai := 0; ai < MAXASSIGNS; ai++ {
			var assign Assign
			if ai < dispatch.AssignsLen {
				assign = dispatch.Assigns[ai]
			} else if ai == dispatch.AssignsLen {
				assign = Assign{}
			} else {
				continue
			}
			prevCost := assign.Cost
			success := assign.AddShip(total_ship+oi, ori, des)
			if !success {
				assign.RemoveShip(total_ship + oi)
				bestCands = append(bestCands, cand{idx: ai, costDelta: 0, feasible: false})
				continue
			}
			assign.GenRoute()
			newCost := assign.Cost
			delta := newCost - prevCost
			if newCost >= 0 && delta >= 0 {
				bestCands = append(bestCands, cand{idx: ai, costDelta: delta, feasible: true})
			} else {
				assign.RemoveShip(total_ship + oi)
				assign.GenRoute()
				bestCands = append(bestCands, cand{idx: ai, costDelta: 0, feasible: false})
			}
		}
		selectedIdx := -1
		minFeasibleDelta := 1e308
		for _, c := range bestCands {
			if c.feasible && c.costDelta < minFeasibleDelta {
				minFeasibleDelta = c.costDelta
				selectedIdx = c.idx
			}
		}
		if selectedIdx < 0 {
			for ai := dispatch.AssignsLen; ai < MAXASSIGNS; ai++ {
				var assign Assign
				if ai < dispatch.AssignsLen {
					assign = dispatch.Assigns[ai]
				} else {
					assign = Assign{}
				}
				success := assign.AddShip(total_ship+oi, ori, des)
				if success {
					assign.GenRoute()
					if assign.Cost >= 0 {
						dispatch.Assigns[ai] = assign
						if ai >= dispatch.AssignsLen {
							dispatch.AssignsLen = ai + 1
						}
						selectedIdx = ai
						break
					} else {
						assign.RemoveShip(total_ship + oi)
						assign.GenRoute()
					}
				}
			}
		}
		if selectedIdx >= 0 && selectedIdx < dispatch.AssignsLen {
			dispatch.Assigns[selectedIdx].AddShip(total_ship+oi, ori, des)
			dispatch.Assigns[selectedIdx].GenRoute()
		} else if selectedIdx >= dispatch.AssignsLen && selectedIdx < MAXASSIGNS {
			var assign Assign
			assign.AddShip(total_ship+oi, ori, des)
			assign.GenRoute()
			dispatch.Assigns[selectedIdx] = assign
			dispatch.AssignsLen = selectedIdx + 1
		} else {
			seedAssignIdx := dispatch.AssignsLen
			if seedAssignIdx >= MAXASSIGNS {
				seedAssignIdx = MAXASSIGNS - 1
			}
			success := dispatch.Assigns[seedAssignIdx].AddShip(total_ship+oi, ori, des)
			if success {
				dispatch.Assigns[seedAssignIdx].GenRoute()
				if dispatch.Assigns[seedAssignIdx].Cost >= 0 {
					if seedAssignIdx >= dispatch.AssignsLen {
						dispatch.AssignsLen = seedAssignIdx + 1
					}
				} else {
					dispatch.Assigns[seedAssignIdx].RemoveShip(total_ship + oi)
					dispatch.Assigns[seedAssignIdx].GenRoute()
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

