	type candidate struct {
		assignIdx int
		pos       int
		delta     float64
		valid     bool
	}
	nOrders := len(oris)
	if nOrders == 0 || len(dess) != nOrders {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	nextAssignIdx := dispatch.AssignsLen
	emptyAssignAvailable := false
	if nextAssignIdx < MAXASSIGNS {
		emptyAssignAvailable = true
	}
	for shipOffset := 0; shipOffset < nOrders; shipOffset++ {
		id := total_ship + shipOffset
		ori := oris[shipOffset]
		des := dess[shipOffset]
		bestCandidate := candidate{valid: false, delta: 1e18}
		totalNonEmpty := 0
		nonEmptyIndices := make([]int, 0, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			if dispatch.Assigns[i].StationsLen > 0 {
				nonEmptyIndices = append(nonEmptyIndices, i)
				totalNonEmpty++
			}
		}
		checkedIndices := make([]int, totalNonEmpty+1)
		copy(checkedIndices[:totalNonEmpty], nonEmptyIndices)
		lastIdx := totalNonEmpty
		if emptyAssignAvailable {
			checkedIndices[lastIdx] = nextAssignIdx
			lastIdx++
		}
		for _, idx := range checkedIndices[:lastIdx] {
			isEmptyRoute := (idx >= dispatch.AssignsLen)
			var tmpAssign Assign
			if !isEmptyRoute {
